sql:
SELECT COUNT(r.release_id) * 1.0 / COUNT(DISTINCT r.created_by) AS average_releases
FROM releases r
WHERE r.deployed_environment = 'staging';

SELECT DISTINCT users.user_id, users.username
FROM users
JOIN releases ON users.user_id = releases.created_by;

SELECT version, status
FROM releases
WHERE release_id = 1;

external_knowledge:
- "stepped out of the factory" metaphorically refers to the latest release date;
- "fresh and sparkling with dew" symbolizes the newest and most recent state;
- "heralding the most recent innovation" emphasizes the selection of the most recent entry in the releases list.

sql:
SELECT users.username, release_access.access_id
FROM users
INNER JOIN release_access ON users.user_id = release_access.user_id;

SELECT user_id, COUNT(*) AS number_of_accesses
FROM release_access
GROUP BY user_id;

SELECT AVG(release_id) AS average_release_id
FROM releases
WHERE created_by = 1;
